import React, {useEffect} from 'react'
import jwt_decode from 'jwt-decode'
import styled from 'styled-components'
import googleIcon from './static/googleIcon.jpg'
import {useSelector, useDispatch} from 'react-redux'
import {accountSelector, handleLogin, openLoginForm} from '../redux/accountSlice'

const GoogleSignIn = styled.label `
width:100%;
height:40px;
font-weight:bold;
font-size:1rem;
border:1px solid #1C1C1C;
border-radius:8px;
display:flex;
align-items:center;
`

const GoogleIcon = styled.div `
position:absolute;
background-image:url(${googleIcon});
width:20px;
height:20px;
background-size:cover;
background-position:center;
margin-left:10px;
`

const Div = styled.div `
margin:0 auto;
`

export default function GoogleLoginBtn () {
	const account = useSelector(accountSelector)
	const dispatch = useDispatch()

	const onGoogleLogin = async () => {
		const result = await fetch('http://localhost:5001/authGoogle')
		const data = await result.text()
		const windowHeight = 600
		const windowWidth = 450
		const top = (window.screen.height/2) - (windowHeight/2)
		const left = (window.screen.width/2) - (windowWidth/2)
		window.open(data,'Google Login',`height=${windowHeight},width=${windowWidth},left=${left},top=${top},resizable=yes`)
	}

	return (
		<GoogleSignIn onClick={onGoogleLogin}>
			<GoogleIcon></GoogleIcon>
			<Div>Continue with Google</Div>
		</GoogleSignIn>
	)
}
